return items.map(item => {
  const data = item.json;

  return {
    json: {
      ...data,
      Email: data["Work Email"] || data["Personal Email"] || '',
      Phone: data["Work Number"] || data["Personal Number"] || '',
      Company: data["Provider Name"] || '',
      Person: data["First Name"] || '',
    }
  };
});

return items.map(item => {
  const data = item.json;

  // Safely extract AI text
  const content =
    data.output?.[0]?.content?.find(c => c.type === "output_text")?.text ||
    data.output?.[0]?.content?.[0]?.text ||
    "{}";

  let parsed = {};
  try {
    parsed = JSON.parse(content);
  } catch (e) {
    parsed = {};
  }

  return {
    json: {
      ...data,

      AI_Category: parsed.category || "",
      AI_LeadScore: parsed.lead_score || "",
      AI_Priority: parsed.priority || "",
      Channel: parsed.recommended_channel || "Email",
      AI_Reason: parsed.reason || "",

      // fallback safety
      AI_Status: parsed.category ? "parsed" : "fallback"
    }
  };
});

return items.map(item => {
  const content =
    item.json.output?.[0]?.content?.find(c => c.type === "output_text")?.text ||
    item.json.output?.[0]?.content?.[0]?.text ||
    "";

  return {
    json: {
      ...item.json,
      AI_FirstMessage: content || `Hi ${item.json.Person}, quick question regarding ${item.json.Company}`
    }
  };
});

return items.map(item => {
  const content =
    item.json.output?.[0]?.content?.find(c => c.type === "output_text")?.text ||
    item.json.output?.[0]?.content?.[0]?.text ||
    "";

  return {
    json: {
      ...item.json,
      AI_FollowupMessage: content || "Just following up on my previous message 🙂"
    }
  };
});

